using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF9 renamed the discriminator property from "Discriminator" to "$type".
        // Keep the old name so existing documents and raw SQL queries still work.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // EF9 changed the id format from "Blog|1" to just "1".
        // Keep the old format so existing documents are still addressable.
        modelBuilder.Entity<Blog>().HasDiscriminatorInJsonId();

        // EF9 Cosmos provider now throws on HasIndex (previously silently ignored).
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}

